const checkpoints = [];

// Load instrumentation and articles
let copy = null;
try {
  const raw = localStorage.getItem('task1_shareUrlCopy');
  copy = raw ? JSON.parse(raw) : null;
} catch (e) {
  copy = null;
}
const articles = JSON.parse(localStorage.getItem('help_articles') || '[]');

// Helper: does article match 'shipping policy template' topic?
const matchesTopic = (article) => {
  const keyword = 'shipping policy template';
  const parts = [];
  if (article.title) parts.push(article.title);
  if (article.summary) parts.push(article.summary);
  if (article.content) parts.push(article.content);
  if (Array.isArray(article.search_keywords)) parts.push(article.search_keywords.join(' '));
  const haystack = parts.join(' ').toLowerCase();
  return haystack.indexOf(keyword) !== -1;
};

// Find candidate articles in Store setup that match the topic
const candidates = articles.filter(a => a && a.category_id === 'store_setup' && matchesTopic(a));
let topArticle = null;
if (candidates.length > 0) {
  topArticle = candidates
    .slice()
    .sort((a, b) => (b.popularity_score || 0) - (a.popularity_score || 0))[0];
}

const copiedArticle = copy ? articles.find(a => a && a.id === copy.article_id) : null;

// CP1 (0.40): Copied share URL for a Store setup article that matches the shipping policy template topic and uses the correct share URL.
const cp1Passed = !!(
  copy &&
  copy.success === true &&
  copiedArticle &&
  copiedArticle.category_id === 'store_setup' &&
  matchesTopic(copiedArticle) &&
  copiedArticle.has_share_link &&
  typeof copy.share_url === 'string' &&
  copy.share_url &&
  copy.share_url === (copiedArticle.share_url || copiedArticle.url || '')
);
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): The copied article is the most popular among all qualifying Store setup shipping policy template articles.
const cp2Passed = !!(
  cp1Passed &&
  topArticle &&
  copiedArticle &&
  topArticle.id === copiedArticle.id
);
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load instrumentation
let lastComparison = null;
try {
  const raw = localStorage.getItem('task2_lastComparison');
  lastComparison = raw ? JSON.parse(raw) : null;
} catch (e) {
  lastComparison = null;
}
const selectedId = localStorage.getItem('task2_selectedCarrierOptionId') || null;

// Load data
const articles = JSON.parse(localStorage.getItem('help_articles') || '[]');
const allOptions = JSON.parse(localStorage.getItem('carrier_options') || '[]');
const carriers = JSON.parse(localStorage.getItem('carriers') || '[]');

// Find the carrier comparison article dynamically
const comparisonArticle = articles.find(a => a && a.has_carrier_comparison);

// Build carrier index
const carrierIndex = {};
carriers.forEach(c => { if (c && c.id) carrierIndex[c.id] = c; });

// Determine filtered options based on the recorded comparison filters
let filteredOptions = [];
if (comparisonArticle && lastComparison) {
  const regionCode = lastComparison.regionCode;
  const minWeightKg = typeof lastComparison.minWeightKg === 'number' ? lastComparison.minWeightKg : null;
  const maxWeightKg = typeof lastComparison.maxWeightKg === 'number' ? lastComparison.maxWeightKg : null;
  const maxCostUsd = typeof lastComparison.maxCostUsd === 'number' ? lastComparison.maxCostUsd : null;

  filteredOptions = allOptions.filter(o => {
    if (!o || !o.is_active) return false;
    if (o.article_id !== comparisonArticle.id) return false;
    if (regionCode && o.region_code !== regionCode) return false;
    // Weight overlap logic matches BusinessLogic
    const minW = o.min_weight_kg;
    const maxW = o.max_weight_kg;
    const minCheck = (typeof minWeightKg === 'number') ? (maxW >= minWeightKg) : true;
    const maxCheck = (typeof maxWeightKg === 'number') ? (minW <= maxWeightKg) : true;
    if (!minCheck || !maxCheck) return false;
    if (typeof maxCostUsd === 'number' && o.price_usd > maxCostUsd) return false;
    // Require an active carrier record
    const carrier = carrierIndex[o.carrier_id];
    if (!carrier || carrier.is_active === false) return false;
    return true;
  });

  // Sort as in getCarrierComparisonOptions for delivery_time_asc
  filteredOptions.sort((a, b) => {
    if (a.delivery_time_min_days !== b.delivery_time_min_days) {
      return a.delivery_time_min_days - b.delivery_time_min_days;
    }
    return a.price_usd - b.price_usd;
  });
}

const fastestOption = filteredOptions.length > 0 ? filteredOptions[0] : null;

// CP1 (0.35): User ran a comparison on the carrier comparison article with correct filters for US, ≤2 kg, under $10, sorted by fastest delivery, and the first option matches the computed fastest option.
const cp1Passed = !!(
  comparisonArticle &&
  lastComparison &&
  lastComparison.article_id === comparisonArticle.id &&
  lastComparison.regionCode === 'united_states' &&
  typeof lastComparison.maxWeightKg === 'number' && lastComparison.maxWeightKg <= 2.0001 &&
  typeof lastComparison.maxCostUsd === 'number' && lastComparison.maxCostUsd <= 10.0001 &&
  lastComparison.sortBy === 'delivery_time_asc' &&
  fastestOption &&
  lastComparison.first_option_id === fastestOption.id
);
checkpoints.push({ passed: cp1Passed, weight: 0.35 });

// CP2 (0.35): User selected the same carrier option as the fastest qualifying option returned by the comparison.
const selectedOption = fastestOption && selectedId ? filteredOptions.find(o => o.id === selectedId) : null;
const cp2Passed = !!(
  cp1Passed &&
  selectedOption &&
  selectedId === lastComparison.first_option_id &&
  selectedId === fastestOption.id
);
checkpoints.push({ passed: cp2Passed, weight: 0.35 });

// CP3 (0.30): The selected carrier option has active carrier setup instructions available (indicating the user could view setup).
let cp3Passed = false;
if (cp2Passed && selectedOption) {
  const carrier = carrierIndex[selectedOption.carrier_id];
  const setupArticle = carrier && carrier.setup_article_id
    ? articles.find(a => a && a.id === carrier.setup_article_id)
    : null;
  cp3Passed = !!(carrier && carrier.is_active !== false && setupArticle);
}
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load instrumentation
let lastVideoStart = null;
try {
  const raw = localStorage.getItem('task3_lastVideoStart');
  lastVideoStart = raw ? JSON.parse(raw) : null;
} catch (e) {
  lastVideoStart = null;
}

const videos = JSON.parse(localStorage.getItem('article_videos') || '[]');
const articles = JSON.parse(localStorage.getItem('help_articles') || '[]');

const video = lastVideoStart ? videos.find(v => v && v.id === lastVideoStart.video_id) : null;
const article = lastVideoStart ? articles.find(a => a && a.id === lastVideoStart.article_id) : null;

// CP1 (0.40): Video start event is tied to a Shopify integration article in the Store Integrations category that has a video tutorial.
const cp1Passed = !!(
  lastVideoStart &&
  article &&
  article.category_id === 'store_integrations' &&
  article.integration_platform === 'shopify' &&
  article.has_video_tutorial &&
  video &&
  video.article_id === article.id
);
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): The started video exists, is under or equal to 600 seconds, and the recorded duration matches the stored metadata.
const cp2Passed = !!(
  cp1Passed &&
  typeof video.duration_seconds === 'number' &&
  video.duration_seconds <= 600 &&
  typeof lastVideoStart.duration_seconds === 'number' &&
  lastVideoStart.duration_seconds === video.duration_seconds
);
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const supportRequests = JSON.parse(localStorage.getItem('support_requests') || '[]');
const articles = JSON.parse(localStorage.getItem('help_articles') || '[]');

// Find the billing article that links to the support form (plan changes guide)
const planArticle = articles.find(a => a && a.category_id === 'billing_subscriptions' && a.contains_support_form_link);

let candidateRequests = [];
if (planArticle) {
  candidateRequests = supportRequests.filter(r => (
    r &&
    r.source_article_id === planArticle.id &&
    r.category === 'billing_subscriptions' &&
    r.topic === 'downgrade_to_basic_plan'
  ));
}

// CP1 (0.40): At least one support request is submitted from the plan changes article with correct category and topic.
const cp1Passed = candidateRequests.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): The request message includes both required phrases about downgrading from Pro to Basic and the $30/month budget.
const phrase1 = 'downgrade from pro to basic';
const phrase2 = 'maximum budget is $30/month';
const cp2Passed = candidateRequests.some(r => {
  const text = ((r.subject || '') + ' ' + (r.message || '')).toLowerCase();
  return text.indexOf(phrase1) !== -1 && text.indexOf(phrase2) !== -1;
});
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load settings (may be stored as array or single object)
let settings = null;
try {
  const raw = localStorage.getItem('order_automation_settings');
  if (raw && raw !== 'null') {
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) {
      settings = parsed.length > 0 ? parsed[parsed.length - 1] : null;
    } else {
      settings = parsed;
    }
  }
} catch (e) {
  settings = null;
}

// Load baseline date if available
let baselineTime = null;
try {
  const mdRaw = localStorage.getItem('_metadata');
  const md = mdRaw ? JSON.parse(mdRaw) : null;
  if (md && md.baselineDate) {
    const t = Date.parse(md.baselineDate);
    if (!isNaN(t)) baselineTime = t;
  }
} catch (e) {
  baselineTime = baselineTime; // ignore
}

let updatedTime = null;
if (settings && settings.updated_at) {
  const t = Date.parse(settings.updated_at);
  if (!isNaN(t)) updatedTime = t;
} else if (settings && settings.created_at) {
  const t = Date.parse(settings.created_at);
  if (!isNaN(t)) updatedTime = t;
}

const meetsConfig = !!(settings && settings.auto_cancel_unfulfilled_enabled === true && settings.auto_cancel_after_days === 7);
let afterBaseline = true;
if (baselineTime != null) {
  afterBaseline = !!(updatedTime != null && updatedTime >= baselineTime);
}

// CP1 (1.00): Auto-cancel is enabled with a 7-day limit, and the setting was last updated on or after the baseline date (when available).
const cp1Passed = meetsConfig && afterBaseline;
checkpoints.push({ passed: cp1Passed, weight: 1.00 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const canned = JSON.parse(localStorage.getItem('canned_responses') || '[]');
const snippets = JSON.parse(localStorage.getItem('article_template_snippets') || '[]');

// Baseline date
let baselineTime = null;
try {
  const mdRaw = localStorage.getItem('_metadata');
  const md = mdRaw ? JSON.parse(mdRaw) : null;
  if (md && md.baselineDate) {
    const t = Date.parse(md.baselineDate);
    if (!isNaN(t)) baselineTime = t;
  }
} catch (e) {
  baselineTime = baselineTime; // ignore
}

// Identify defective-item return template snippet IDs
const defectiveSnippetIds = snippets
  .filter(s => s && s.snippet_type === 'defective_item_return')
  .map(s => s.id);

// Candidate canned responses created from the defective template with correct title/folder
let candidates = canned.filter(r => (
  r &&
  r.title === 'Defective item return - template A' &&
  r.folder === 'Returns & refunds' &&
  defectiveSnippetIds.indexOf(r.source_template_snippet_id || '') !== -1
));

// Only consider responses created/updated on or after the baseline date (if available)
if (baselineTime != null) {
  candidates = candidates.filter(r => {
    const tsStr = r.updated_at || r.created_at || '';
    const t = Date.parse(tsStr);
    return !isNaN(t) && t >= baselineTime;
  });
}

// CP1 (0.60): A qualifying canned response from the defective-item template exists in the 'Returns & refunds' folder with the correct title, created after the baseline date.
const cp1Passed = candidates.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.60 });

// CP2 (0.40): Its body contains '10% discount' and no remaining [DISCOUNT] placeholder.
const cp2Passed = candidates.some(r => {
  const body = r.body || '';
  const lower = body.toLowerCase();
  const hasDiscount = lower.indexOf('10% discount') !== -1;
  const hasPlaceholder = body.indexOf('[DISCOUNT]') !== -1;
  return hasDiscount && !hasPlaceholder;
});
checkpoints.push({ passed: cp2Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const incidentReports = JSON.parse(localStorage.getItem('incident_reports') || '[]');
const incidents = JSON.parse(localStorage.getItem('status_incidents') || '[]');
const services = JSON.parse(localStorage.getItem('status_services') || '[]');

// Find Product Sync service IDs
const productSyncServiceIds = services
  .filter(s => s && s.slug === 'product_sync')
  .map(s => s.id);

// Incidents that affect Product Sync
const productSyncIncidentIds = incidents
  .filter(inc => inc && Array.isArray(inc.affected_service_ids) && inc.affected_service_ids.some(id => productSyncServiceIds.indexOf(id) !== -1))
  .map(inc => inc.id);

// Reports tied to Product Sync incidents
const relevantReports = incidentReports.filter(r => r && productSyncIncidentIds.indexOf(r.incident_id) !== -1);

// CP1 (0.40): At least one report is tied to a Product Sync incident with medium severity.
const cp1Passed = relevantReports.some(r => r.severity === 'medium');
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): The report subject and description include the required SYNC_409 phrases with medium severity.
const subjPhrase = 'sync_409 product feed not updating';
const descPhrase = 'sync_409 error for product feed updates';
const cp2Passed = relevantReports.some(r => {
  if (r.severity !== 'medium') return false;
  const subject = (r.subject || '').toLowerCase();
  const desc = (r.description || '').toLowerCase();
  return subject.indexOf(subjPhrase) !== -1 && desc.indexOf(descPhrase) !== -1;
});
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Load settings (may be array or single object)
let settings = null;
try {
  const raw = localStorage.getItem('payout_settings');
  if (raw && raw !== 'null') {
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) {
      settings = parsed.length > 0 ? parsed[parsed.length - 1] : null;
    } else {
      settings = parsed;
    }
  }
} catch (e) {
  settings = null;
}

// Load baseline date
let baselineTime = null;
try {
  const mdRaw = localStorage.getItem('_metadata');
  const md = mdRaw ? JSON.parse(mdRaw) : null;
  if (md && md.baselineDate) {
    const t = Date.parse(md.baselineDate);
    if (!isNaN(t)) baselineTime = t;
  }
} catch (e) {
  baselineTime = baselineTime; // ignore
}

let updatedTime = null;
if (settings && settings.updated_at) {
  const t = Date.parse(settings.updated_at);
  if (!isNaN(t)) updatedTime = t;
} else if (settings && settings.created_at) {
  const t = Date.parse(settings.created_at);
  if (!isNaN(t)) updatedTime = t;
}

const meetsConfig = !!(settings && settings.payout_frequency === 'weekly' && settings.minimum_payout_amount === 100 && settings.currency === 'usd');
let afterBaseline = true;
if (baselineTime != null) {
  afterBaseline = !!(updatedTime != null && updatedTime >= baselineTime);
}

// CP1 (1.00): Payouts are set to weekly with a $100 USD threshold, and the settings were updated on or after the baseline date (when available).
const cp1Passed = meetsConfig && afterBaseline;
checkpoints.push({ passed: cp1Passed, weight: 1.00 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
